from flask import Flask, jsonify, make_response, redirect, url_for

app = Flask(__name__)

@app.route("/")
def index():
    return redirect(url_for("api_info"))

@app.route("/api/info")
def api_info():
    resp = make_response(jsonify({
        "app": "MyApp",
        "version": "1.0.0",
        "status": "running"
    }), 200)
    resp.headers["X-API-Version"] = "1.0"
    return resp

@app.route("/api/error")
def error():
    return jsonify({"error": "Not found"}), 404
